using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr documents = app->documents();
    if (!documents)
        return false;

    Ptr doc = documents->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    design->designType(ParametricDesignType);

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    Ptr feats = rootComp->features();
    if (!feats)
        return false;

    // Create a base feature
    Ptr baseFeats = feats->baseFeatures();
    if (!baseFeats)
        return false;

    Ptr baseFeat = baseFeats->add();
    if (!baseFeat)
        return false;

    baseFeat->startEdit();

    // Create construction plane in base feature
    Ptr planes = rootComp->constructionPlanes();
    if (!planes)
        return false;
    Ptr planeInput = planes->createInput();
    if (!planeInput)
        return false;
    planeInput->targetBaseOrFormFeature(baseFeat);
    planeInput->setByOffset(rootComp->xYConstructionPlane(), ValueInput::createByReal(1));
    Ptr plane = planes->add(planeInput);
    if (!plane)
        return false;

    // Create sketch in base feature
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;
    Ptr xyPlane = rootComp->xYConstructionPlane();
    if (!xyPlane)
        return false;
    Ptr sketch = sketches->addToBaseOrFormFeature(xyPlane, baseFeat, true);
    if (!sketch)
        return false;

    // Draw a circle.
    Ptr sketchCurves = sketch->sketchCurves();
    if (!sketchCurves)
        return false;
    Ptr circles = sketchCurves->sketchCircles();
    if (!circles)
        return false;
    Ptr centerPoint = Point3D::create(0, 0, 0);
    if (!centerPoint)
        return false;
    Ptr circle1 = circles->addByCenterRadius(centerPoint, 2);
    if (!circle1)
        return false;

    // Get the profile defined by the circle.
    Ptr profs = sketch->profiles();
    if (!profs)
        return false;
    Ptr prof = profs->item(0);
    if (!prof)
        return false;

    // Create an extrusion input to be able to define the input needed for an extrusion
    // while specifying the profile and that a new component is to be created
    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;
    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);
    if (!extInput)
        return false;

    // Define that the extent is a distance extent of 5 cm.
    Ptr distance = ValueInput::createByReal(5);
    if (!distance)
        return false;
    extInput->setDistanceExtent(false, distance);
    extInput->targetBaseFeature(baseFeat);

    // Create the extrusion.
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    return true;
}
